    "pro.table.row3": "Serveur IPTV local",
    "pro.table.row4": "Tous les formats d'exportation",
    "pro.table.row4.free": "M3U seulement",
    "pro.table.row5": "Moteur de lecture FFmpeg",
    "pro.table.row6": "Lecteur plein écran",
