    "nav.comingSoon": "Sắp ra mắt",
    "hero.badge": "Mới &nbsp;·&nbsp; Làm mới thông minh với phát hiện xung đột →",
    "hero.headline": "Danh sách phát của bạn,<br><em>hoàn toàn ngăn nắp.</em>",
    "hero.sub": "Nhập, quản lý và phát M3U playlist với ứng dụng Mac và iPhone thuần túy dành cho người dùng chuyên nghiệp.",
    "hero.button": "Sắp ra mắt",
